using UnityEngine;

/// <summary>
/// Habilidade de planar (GLD do GDD): enquanto o botão de habilidade estiver
/// pressionado e o player estiver no ar, reduz a gravidade e limita a
/// velocidade de queda, criando uma "queda lenta" (ex.: Coruja, Arara,
/// Garça, Galinha em modo "flutter-lite").
///
/// Activada via PrimaryAbility.Glide: AbilityRouter chama StartGlide() em
/// OnAbilityPressed e StopGlide() em OnAbilityReleased. Também termina
/// automaticamente se o player aterrar ou tiver o movimento bloqueado
/// (ex.: durante um Dash).
///
/// Correntes térmicas (P8 — Arara H2): zonas <see cref="ThermalCurrent"/>
/// leem 'IsGliding' e, enquanto true e dentro da zona, empurram o player para
/// cima (ganha altura) em vez de só limitar a queda.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class GlideAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private bool enabledForForm;

    private float glideGravityScale;
    private float glideFallSpeed;
    private float normalGravityScale;

    private bool isGliding;

    /// <summary>true enquanto o player está activamente a planar.</summary>
    public bool IsGliding => isGliding;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.canGlide;

        if (!enabledForForm)
        {
            StopGlide();
            return;
        }

        glideGravityScale = form.glideGravityScale;
        glideFallSpeed = form.glideFallSpeed;
        normalGravityScale = form.gravityScale > 0f ? form.gravityScale : rb.gravityScale;
    }

    /// <summary>
    /// Chamado pelo AbilityRouter (OnAbilityPressed) quando a forma actual
    /// tem PrimaryAbility.Glide. Só inicia o glide se o player estiver no ar
    /// e sem o movimento bloqueado (ex.: a meio de um Dash).
    /// </summary>
    public void StartGlide()
    {
        if (!enabledForForm) return;
        if (motor.MovementLocked) return;
        if (motor.IsGrounded) return;

        isGliding = true;
        rb.gravityScale = glideGravityScale;
    }

    /// <summary>
    /// Chamado pelo AbilityRouter (OnAbilityReleased) ou internamente quando
    /// o glide precisa de terminar (aterrou, movimento bloqueado, troca de
    /// forma). Restaura a gravidade normal da forma.
    /// </summary>
    public void StopGlide()
    {
        if (!isGliding) return;

        isGliding = false;
        rb.gravityScale = normalGravityScale;
    }

    private void FixedUpdate()
    {
        if (!isGliding) return;

        // Pousou ou algo bloqueou o movimento (ex.: Dash) -> cancela o glide.
        if (motor.IsGrounded || motor.MovementLocked)
        {
            StopGlide();
            return;
        }

        // Limita a velocidade de queda (eixo Y negativo = a cair).
        if (rb.linearVelocity.y < -glideFallSpeed)
            rb.linearVelocity = new Vector2(rb.linearVelocity.x, -glideFallSpeed);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // "Hold": Activate/Release mapeiam para Start/StopGlide; Cancel também
    // termina o glide (transformar, morrer, etc.). Sem cooldown.
    void IAbility.Activate() => StartGlide();
    void IAbility.Release() => StopGlide();
    public void Cancel(AbilityCancelReason reason) => StopGlide();
    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => isGliding;
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm && !isGliding && !motor.MovementLocked && !motor.IsGrounded;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
